#include <stdio.h>
#include <stdlib.h>

int main() {
    long long Q;
    if (scanf("%lld", &Q) != 1) return 0;
    long long *stack = (long long *)malloc(sizeof(long long) * Q);
    long long top = 0;
    for (long long i = 0; i < Q; ++i) {
        int type;
        if (scanf("%d", &type) != 1) break;
        if (type == 1) {
            long long N;
            scanf("%lld", &N);
            stack[top++] = N;
        } else if (type == -1) {
            if (top == 0) {
                printf("kuchbhi?\n");
            } else {
                printf("%lld\n", stack[--top]);
            }
        }
    }
    free(stack);
    return 0;
}

