#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    Q = int(next(it))
    stack = []
    out_lines = []
    for _ in range(Q):
        typ = int(next(it))
        if typ == 1:
            N = int(next(it))
            stack.append(N)
        else:  # typ == -1
            if stack:
                out_lines.append(str(stack.pop()))
            else:
                out_lines.append("kuchbhi?")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

